options.getOption:
const frames = context.panel.data.series || [];
let grid = null, thr = null;
const flags = [];
for (const f of frames) {
  const vf = f.fields.find((x) => x.type === 'number');
  if (!vf) { continue; }
  if (vf.name === 'Grid power (kW)') { grid = f; continue; }
  if (vf.labels && vf.labels.ts) { flags.push(f); continue; }
  thr = f;
}
const slots = [];
for (const f of flags) {
  const vf = f.fields.find((x) => x.type === 'number');
  const vals = vf.values;
  let on = false;
  for (let i = 0; i < vals.length; i++) { if (Number(vals[i]) >= 1) { on = true; break; } }
  if (on) { slots.push(Number(vf.labels.ts)); }
}
slots.sort((a, b) => a - b);
const gridData = [];
let gridT = [], gridV = [];
if (grid) {
  const tf = grid.fields.find((x) => x.type === 'time');
  const vf = grid.fields.find((x) => x.type === 'number');
  gridT = tf.values; gridV = vf.values;
  for (let i = 0; i < gridT.length; i++) { if (gridV[i] != null) { gridData.push([gridT[i], Number(Number(gridV[i]).toFixed(3))]); } }
}
let thrVal = null;
if (thr) {
  const vf = thr.fields.find((x) => x.type === 'number');
  if (vf && vf.values.length > 0) { thrVal = Number(vf.values[vf.values.length - 1]); }
}
const nowMs = Date.now();
const past = slots.filter((ts) => ts + 900000 <= nowMs);
let score = 'Predicted peak slots in range: ' + slots.length + ' (' + past.length + ' already past — scoring appears once predictions age past their slot)';
if (past.length > 0 && gridData.length > 0) {
  const rs = [];
  for (let i = 0; i < gridT.length; i++) { if (gridV[i] != null) { rs.push({ start: gridT[i] - 900000, kw: Number(gridV[i]) }); } }
  const K = Math.min(past.length, rs.length);
  const top = rs.slice().sort((a, b) => b.kw - a.kw).slice(0, K).map((x) => x.start);
  const hits = past.filter((ts) => top.indexOf(ts) >= 0).length;
  score = 'Hits ' + hits + '/' + K + ' (past predicted slots in realized top-' + K + ') · misses ' + (K - hits) + ' · false alarms ' + (past.length - hits);
}
const xMax = slots.length > 0 ? Math.max(nowMs, slots[slots.length - 1] + 900000 + 3600000) : null;
const xAxis = { type: 'time' };
if (xMax) { xAxis.max = xMax; }
const mainSeries = {
  name: 'Grid power (kW)',
  type: 'line',
  showSymbol: false,
  lineStyle: { width: 1.5, color: '#5794f2' },
  areaStyle: { opacity: 0.12, color: '#5794f2' },
  data: gridData,
  markArea: { itemStyle: { color: 'rgba(242, 73, 92, 0.28)' }, data: slots.map((ts) => [{ xAxis: ts }, { xAxis: ts + 900000 }]) }
};
if (thrVal != null) {
  mainSeries.markLine = { symbol: 'none', lineStyle: { type: 'dashed', color: '#ff9830' }, label: { formatter: 'peak threshold ' + thrVal.toFixed(2) + ' kW', position: 'insideEndTop' }, data: [{ yAxis: thrVal }] };
}
return {
  backgroundColor: 'transparent',
  title: { text: score, left: 'center', top: 0, textStyle: { fontSize: 12, fontWeight: 'normal' } },
  tooltip: { trigger: 'axis' },
  grid: { left: 55, right: 20, top: 34, bottom: 35 },
  xAxis: xAxis,
  yAxis: { type: 'value', name: 'kW' },
  series: [mainSeries]
};

const s = context.panel.data.series[0];
if (!s) { return {}; }
const tF = s.fields.find((x) => x.type === 'time');
const vF = s.fields.find((x) => x.type === 'number');
if (!tF || !vF) { return {}; }
const t = tF.values, v = vF.values;
const fmt = new Intl.DateTimeFormat('en-GB', { timeZone: 'Europe/Brussels', weekday: 'short', hour: '2-digit', hour12: false });
const days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
const sum = {}, cnt = {};
for (let i = 0; i < t.length; i++) {
  if (v[i] == null) { continue; }
  const parts = fmt.formatToParts(t[i] - 3600000);
  const wd = parts.find((p) => p.type === 'weekday').value;
  let hr = parseInt(parts.find((p) => p.type === 'hour').value, 10);
  if (hr === 24) { hr = 0; }
  const key = wd + '|' + hr;
  sum[key] = (sum[key] || 0) + Number(v[i]);
  cnt[key] = (cnt[key] || 0) + 1;
}
const data = [];
Object.keys(sum).forEach((key) => {
  const p = key.split('|');
  const d = days.indexOf(p[0]);
  const h = parseInt(p[1], 10);
  if (d >= 0 && h >= 0 && h < 24) { data.push([h, d, Number((sum[key] / cnt[key]).toFixed(3)), cnt[key]]); }
});
const hours = Array.from({ length: 24 }, (_, h) => String(h).padStart(2, '0'));
return {
  backgroundColor: 'transparent',
  tooltip: { position: 'top', formatter: (p) => days[p.value[1]] + ' ' + hours[p.value[0]] + ':00 — ' + (p.value[2] >= 0 ? '+' : '') + p.value[2] + ' kWh (forecast − realized, n=' + p.value[3] + ')' },
  grid: { left: 50, right: 70, top: 10, bottom: 40 },
  xAxis: { type: 'category', data: hours, name: 'hour', splitArea: { show: true } },
  yAxis: { type: 'category', data: days, inverse: true, splitArea: { show: true } },
  visualMap: { min: -1, max: 1, calculable: true, orient: 'vertical', right: 0, top: 'center', inRange: { color: ['#c4162a', '#f2495c', '#f7f7f7', '#5794f2', '#1f60c4'] } },
  series: [{ type: 'heatmap', data: data, emphasis: { itemStyle: { shadowBlur: 6 } } }]
};
